using System.Text.RegularExpressions;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // ──────────────────────────────────────────────
    //  FormatPhoneNumber
    // ──────────────────────────────────────────────

    [TestMethod]
    public void FormatPhoneNumber_StartsWithAreaCodeInParentheses()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.StartsWith(result, "(212)");
    }

    [TestMethod]
    public void FormatPhoneNumber_EndsWithLastFourDigits()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ContainsDashSeparator()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Contains(result, "-");
    }

    [TestMethod]
    public void FormatPhoneNumber_MatchesExpectedPattern()
    {
        string result = _formatter.FormatPhoneNumber("2125551234");

        StringAssert.Matches(result, new Regex(@"^\(\d{3}\) \d{3}-\d{4}$"));
    }

    [TestMethod]
    public void FormatPhoneNumber_ReturnsExactFormat()
    {
        string result = _formatter.FormatPhoneNumber("8005551234");

        Assert.AreEqual("(800) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullDigits_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(
            () => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.FormatPhoneNumber(digits));
    }

    // ──────────────────────────────────────────────
    //  BuildGreeting
    // ──────────────────────────────────────────────

    [TestMethod]
    public void BuildGreeting_StartsWithDear()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear ");
    }

    [TestMethod]
    public void BuildGreeting_EndsWithComma()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, ",");
    }

    [TestMethod]
    public void BuildGreeting_ContainsName()
    {
        string result = _formatter.BuildGreeting("Johnson");

        StringAssert.Contains(result, "Johnson");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_ContainsMr()
    {
        string result = _formatter.BuildGreeting("Smith");

        StringAssert.Contains(result, "Mr.");
        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_UsesProvidedTitle()
    {
        string result = _formatter.BuildGreeting("Smith", "Dr.");

        StringAssert.Contains(result, "Dr.");
        Assert.AreEqual("Dear Dr. Smith,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_Throws(string? name)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.BuildGreeting(name!));
    }

    // ──────────────────────────────────────────────
    //  GenerateSlug
    // ──────────────────────────────────────────────

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        string result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_DoesNotStartWithDash()
    {
        string result = _formatter.GenerateSlug("  --Hello--  ");

        StringAssert.DoesNotMatch(result, new Regex("^-"));
    }

    [TestMethod]
    public void GenerateSlug_DoesNotEndWithDash()
    {
        string result = _formatter.GenerateSlug("  --Hello--  ");

        StringAssert.DoesNotMatch(result, new Regex("-$"));
    }

    [TestMethod]
    public void GenerateSlug_SpecialCharacters_ReplacedWithDashes()
    {
        string result = _formatter.GenerateSlug("C# is Great!!!");

        StringAssert.Matches(result, new Regex("^[a-z0-9-]+$"));
        Assert.AreEqual("c-is-great", result);
    }

    [TestMethod]
    public void GenerateSlug_MixedCase_ReturnsAllLowercase()
    {
        string result = _formatter.GenerateSlug("My AWESOME Post");

        StringAssert.DoesNotMatch(result, new Regex("[A-Z]"));
        Assert.AreEqual("my-awesome-post", result);
    }

    [TestMethod]
    public void GenerateSlug_ConsecutiveSpaces_CollapsedToSingleDash()
    {
        string result = _formatter.GenerateSlug("hello    world");

        StringAssert.DoesNotMatch(result, new Regex("--"));
        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_Throws(string? title)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _formatter.GenerateSlug(title!));
    }

    // ──────────────────────────────────────────────
    //  FormatCurrency
    // ──────────────────────────────────────────────

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        string result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        string result = _formatter.FormatCurrency(9.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_TwoDecimalPlaces()
    {
        string result = _formatter.FormatCurrency(5m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_RoundsToTwoDecimals()
    {
        string result = _formatter.FormatCurrency(1.999m);

        StringAssert.Matches(result, new Regex(@"\.\d{2}$"));
        Assert.AreEqual("$2.00", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinus()
    {
        string result = _formatter.FormatCurrency(-42.50m);

        StringAssert.Contains(result, "-");
        Assert.AreEqual("$-42.50", result);
    }

    [TestMethod]
    public void FormatCurrency_Zero_ReturnsZeroFormatted()
    {
        string result = _formatter.FormatCurrency(0m);

        Assert.AreEqual("$0.00", result);
    }

    [TestMethod]
    public void FormatCurrency_LargeAmount_FormatsCorrectly()
    {
        string result = _formatter.FormatCurrency(1234567.89m);

        StringAssert.StartsWith(result, "$");
        StringAssert.EndsWith(result, "7.89");
    }
}

